const xml = $input.first().json.data;
const now = new Date();

// Parse file list from WebDAV XML
const filePattern = /<d:href>([^<]+)<\/d:href>/gi;
const files = [];
let match;

while ((match = filePattern.exec(xml)) !== null) {
  const href = decodeURIComponent(match[1]);
  if (href.match(/n8n_backup.*\.json$/i)) {
    const fileName = href.split('/').pop();
    files.push(fileName);
  }
}

// Parse dates from filenames
const backups = files.map(f => {
  const dateMatch = f.match(/n8n_backup_(\d{4}-\d{2}-\d{2})/);
  if (!dateMatch) return null;
  return {
    fileName: f,
    date: new Date(dateMatch[1]),
    isBaseline: f.includes('BASELINE'),
    isWeekly: f.includes('WEEKLY'),
    isMonthly: f.includes('MONTHLY'),
    isYearly: f.includes('YEARLY')
  };
}).filter(b => b !== null);

// Retention rules
const sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000);
const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);
const oneYearAgo = new Date(now - 365 * 24 * 60 * 60 * 1000);

const toKeep = [];
const toDelete = [];

// Group by week and month for retention
const weeklyKeepers = new Map(); // week key -> newest backup
const monthlyKeepers = new Map(); // month key -> newest backup

for (const backup of backups) {
  // Always keep special backups
  if (backup.isBaseline || backup.isWeekly || backup.isMonthly || backup.isYearly) {
    toKeep.push({ ...backup, reason: 'special' });
    continue;
  }

  // Keep all from last 7 days
  if (backup.date >= sevenDaysAgo) {
    toKeep.push({ ...backup, reason: 'recent (< 7 days)' });
    continue;
  }

  // For 7-30 days: keep one per week
  if (backup.date >= thirtyDaysAgo) {
    const weekKey = `${backup.date.getFullYear()}-W${Math.ceil((backup.date - new Date(backup.date.getFullYear(), 0, 1)) / (7 * 24 * 60 * 60 * 1000))}`;
    if (!weeklyKeepers.has(weekKey) || backup.date > weeklyKeepers.get(weekKey).date) {
      weeklyKeepers.set(weekKey, backup);
    }
    continue;
  }

  // For 30-365 days: keep one per month  
  if (backup.date >= oneYearAgo) {
    const monthKey = `${backup.date.getFullYear()}-${backup.date.getMonth()}`;
    if (!monthlyKeepers.has(monthKey) || backup.date > monthlyKeepers.get(monthKey).date) {
      monthlyKeepers.set(monthKey, backup);
    }
    continue;
  }

  // Older than 1 year: delete (we'll keep yearly separately)
  toDelete.push({ ...backup, reason: 'older than 1 year' });
}

// Add weekly and monthly keepers
for (const [week, backup] of weeklyKeepers) {
  toKeep.push({ ...backup, reason: `weekly keeper (${week})` });
}
for (const [month, backup] of monthlyKeepers) {
  toKeep.push({ ...backup, reason: `monthly keeper (${month})` });
}

// Find files to delete (those not in toKeep)
const keepFileNames = new Set(toKeep.map(b => b.fileName));
for (const backup of backups) {
  if (!keepFileNames.has(backup.fileName) && !toDelete.find(d => d.fileName === backup.fileName)) {
    toDelete.push({ ...backup, reason: 'not needed for retention' });
  }
}

return [{
  json: {
    totalBackups: backups.length,
    keeping: toKeep.length,
    deleting: toDelete.length,
    toDelete: toDelete.map(b => b.fileName),
    summary: `Found ${backups.length} backups. Keeping ${toKeep.length}, deleting ${toDelete.length}.`
  }
}];
